## Section1(not reported)
## Problem1(1.2.9.4)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "contextFiniteSolutionSets.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Fraction");
$var = list_random('a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
Context()->variables->are($var => 'Real');
do {
  ($a, $b) = random_coprime([1..10], [2..10,12]);
  ($c, $d) = random_coprime([1..10], [2..10,12]);
} until ($b != $d);
$A = Fraction($a, $b);
$B = Fraction($c, $d);
$B = random(0,1) ? $B : -$B;
$left = Formula("$A + $var")->reduce;
$right = Formula("$B")->reduce;
Context("FiniteSolutionSets");
Context()->variables->are($var => 'Real');
$solution = $B - $A;
$solset = Formula("{$solution}");

############################################################
# Body
############################################################

BEGIN_PGML
Solve the equation.

[`[$left]=[$right]`]

[_]{$solset}{10}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
The opposite action to addition is subtraction.

[```\newcommand{\subtractright}[1]{{\highlight{{{}-#1}}}}\newcommand{\amp}{&}
\begin{aligned}
[$left] \amp= [$right]\\
[$left]\subtractright{[$A]} \amp= [$right]\subtractright{[$A]}\\
[$var] \amp= [$solution]
\end{aligned}
```]

The solution set is [`[$solset]\text{.}`]

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
